import subprocess
import os

def convertDocument(input_file, output_file, conversion_format):
    if not os.path.isfile(input_file):
        raise FileNotFoundError(f"The input file {input_file} does not exist.")
    
    command = [
        'libreoffice',
        '--headless',
        '--convert-to',
        conversion_format,
        '--outdir',
        os.path.dirname(output_file),
        input_file
    ]
    
    subprocess.run(command, check=True)
    
    # Rename the output file if necessary
    output_temp = os.path.join(os.path.dirname(input_file), os.path.splitext(os.path.basename(input_file))[0] + '.' + conversion_format)
    if os.path.isfile(output_temp):
        os.rename(output_temp, output_file)